import{_ as t,o as n,c as o,a3 as i}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"17. Union Rights","description":"","frontmatter":{"title":"17. Union Rights","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["union-matters"]},"headers":[],"relativePath":"ebas/mspp/union-rights/17-union-rights.md","filePath":"ebas/mspp/union-rights/17-union-rights.md"}'),a={name:"ebas/mspp/union-rights/17-union-rights.md"};function r(s,e,l,p,c,h){return n(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="_17-union-rights" tabindex="-1">17. Union Rights <a class="header-anchor" href="#_17-union-rights" aria-label="Permalink to &quot;17. Union Rights&quot;">​</a></h1><p><strong>17.1</strong> Access to Employees – General The Union will have access to Employees for any process arising under this Agreement.</p><p><strong>17.2</strong> Access to Employees – Electronic communication The Employer will ensure that:</p><p><strong>a.</strong> emails from the Union domain name are not blocked or restricted by or on behalf of the Employer, except in respect of any individual Employee who has made a written request to the Employer to block such emails;</p><p><strong>b.</strong> emails from Employees to the Union are not blocked or restricted by or on behalf of the Employer;</p><p><strong>c.</strong> access from health service computers and like devices to Union websites and online information is not blocked, or limited; and</p><p><strong>d.</strong> where a genuine security concern arises regarding the above, the Employer will immediately notify the Union to enable the security concern to be addressed.</p><p><strong>17.3</strong> Access to Employees – Orientation</p><p><strong>a.</strong> For the purposes of facilitating the orientation of new Employees and in particular to familiarise such Employees with the operation of this Agreement, the Union shall be provided, in writing on a quarterly basis, with the dates, times and venues of any orientation/induction program involving new Employees and be permitted to attend and address the new Employees. If the dates of these programs are fixed in advance for a regular day and time then a list will be sent to the Union as soon as such dates are fixed.</p><p><strong>b.</strong> An Employer will advise the Union of the date, time and location of orientation/induction programs not less than 14 days prior to the program.</p><p><strong>c.</strong> Those covered by this Agreement acknowledge the increasing role that technology plays in orientation / induction. An Employer and Union may agree to an alternative means by which the Union can access new Employees, including where orientation / induction programs are conducted on-line or the Union cannot reasonably attend.</p><p><strong>17.4</strong> Delegates and HSRs NOTE: Additional rights of HSRs are contained in the OHS Act.</p><p><strong>a.</strong> In this subclause 17.4 Representative means a Union Delegate or HSR.</p><p><strong>b.</strong> A Representative is entitled to reasonable time release from duty to:</p><p><strong>(i)</strong> attend to matters relating to industrial, occupational health and safety or other relevant matters such as assisting with grievance procedures and attending committee meetings;</p><p><strong>(ii)</strong> access reasonable preparation time before meetings with management disciplinary or grievance meetings with a Union member;</p><p><strong>(iii)</strong> appear as a witness or participate in conciliation or arbitration, before the Commission;</p><p><strong>(iv)</strong> present information on the Union at orientation sessions for new Employees.</p><p><strong>c.</strong> A Representative required to attend management or consultative meetings outside of paid time will be paid to attend.</p><p><strong>d.</strong> A Representative will be provided with access to facilities such as telephones, computers, email, noticeboards and meeting rooms in a manner that does not adversely affect service delivery and work requirements of the Employer. In the case of a HSR, facilities will include other facilities as necessary to enable them to perform their functions as prescribed under the OHS Act.</p><p><strong>17.5</strong> Noticeboard</p><p><strong>a.</strong> A noticeboard for the Union’s use will be readily accessible in each ward/unit/work area or nearest staff room where persons eligible to be members of the Union are employed.</p><p><strong>b.</strong> The Union and members covered by this Agreement will, during the life of this Agreement, consult over the development of an electronic noticeboard managed by the Union.</p><p><strong>17.6</strong> Meeting Space In the absence of agreement on a location for the holding of Union meetings, the room where one or more of the Employees who may participate in the meeting ordinarily take meal or other breaks will be the meeting room for the purpose of Union meetings. Nothing in this clause is intended to override the operation of the Act.</p><p><strong>17.7</strong> Secondment to the Union The Employer will, on application, grant leave without pay, in writing, to an Employee for the purpose of secondment to work for the Union subject to the Employer’s reasonable operational requirements. Such absence will not break service but not count as service for Long Service Leave purposes.</p><p><strong>17.8</strong> Employees holding union official positions The Employer will, on application by the Union, grant leave without loss of pay to an Employee for the purpose of fulfilling their duties as an official of the Union, which includes participation on National Council or management committees. For the purposes of this clause Union includes the HSU and the MSAV, VPA and AHP, its component Associations.</p><p><strong>17.9</strong> Union Training NOTE: an HSR may be entitled to any training in accordance with the OHS Act rather than, or in addition to, this clause.</p><p><strong>a.</strong> Subject to the conditions in this subclause 17.9, Employees selected by their Union to attend training courses on industrial relations and/or health and safety will be entitled to a maximum of five days’ paid leave per calendar year per Employee.</p><p><strong>b.</strong> Leave in excess of five days and up to ten days may be granted in a calendar year subject to the total leave being granted in that year and in the subsequent year not exceeding ten days.</p><p><strong>c.</strong> The granting of leave will be subject to the Employer’s operational requirements. The granting of leave will not be unreasonably withheld.</p><p><strong>d.</strong> Leave under this subclause is granted on the following conditions:</p><p><strong>(i)</strong> applications are accompanied by a statement from the Union advising that it has nominated the Employee or supports the application:</p><p><strong>(ii)</strong> the training is conducted by the Union, an association of unions or accredited training provider; and</p><p><strong>(iii)</strong> the application is made as early as practicable and not less than two (2) weeks before the training.</p><p><strong>e.</strong> The Employee will be paid ‘ordinary time earnings’ where ordinary pay is the rate of pay for normal rostered hours plus experience/service payments plus allowances which are deemed pursuant to this Agreement to be part of pay for all purposes, but excluding shift work, overtime and other allowances.</p><p><strong>f.</strong> Leave in accordance with this clause may include necessary travelling time in normal hours immediately before or after the course.</p><p><strong>g.</strong> Leave granted under this clause will count as service for all purposes of this Agreement.</p><p><strong>h.</strong> Expenses associated with attendance at training courses, including fares, accommodation and meal costs are not the responsibility of the Employer.</p><p><strong>17.10</strong> Workplace Implementation and Compliance Committee</p><p><strong>a.</strong> A local Workplace Implementation and Compliance Committee (WICC) will continue or, if there is not currently a WICC in operation, be established at each Employer. Having regard for the size and location, a WICC may be appropriate at each facility/campus. The WICC will, where practicable, comprise equal numbers of representatives of the Employer and the Union for the purposes of:</p><p><strong>(i)</strong> Agreement implementation;</p><p><strong>(ii)</strong> on-going monitoring and assessment of the implementation of this Agreement; and</p><p><strong>(iii)</strong> to deal with any local disputes that may arise, without limiting the Dispute Settling Procedure in <a href="/eba/ebas/mspp/disputes/11-disputes-settling-procedures.html">clause 11</a> of this Agreement.</p><p><strong>b.</strong> Each Employer shall, within three months of the Agreement coming into operation, provide to the Union a plan to ensure the observance and compliance with the Agreement. Such plan may include, for example, steps taken or proposed, to inform managers as to the Employer’s obligations under the Agreement.</p><p><strong>c.</strong> In addition, each Employer shall provide to the WICC, on a regular basis, information which would provide insight into workload. Relevant information could include:</p><p><strong>(i)</strong> Current EFT by department</p><p><strong>(ii)</strong> Vacancies</p><p><strong>(iii)</strong> Personal leave levels</p><p><strong>(iv)</strong> Planned and unplanned absences in accordance with <a href="/eba/ebas/mspp/workforce-management/34-planned-and-unplanned-absences.html">clause 34.8</a></p><p><strong>(v)</strong> Number of complaints relevant to workload</p><p><strong>(vi)</strong> Notifiable incidents</p><p><strong>(vii)</strong> Annual leave accruals</p><p><strong>(viii)</strong> Overtime</p><p><strong>d.</strong> Priority items for consideration by the WICC will include Agreement compliance and the matters arising under <a href="/eba/ebas/mspp/leave/82-family-violence-leave.html">clause 82</a> (Family Violence); clause 17 (Union Rights) and other matters that may be identified by the parties as being of relevance.</p><p><strong>e.</strong> Each Employer shall report and review all DWGs to ensure that all workplaces are mapped, known and have Employee elected and trained HSRs to ensure improvements in workplace safety.</p><p><strong>17.11</strong> The exercise of any right of entry conferred by clause 17 which involves entry to premises for a purpose referred to in s.481 of the Act, or to hold discussions of a kind referred to in s.484 of the Act, will be in accordance with the requirements of Part 3-4 of Chapter 3 of the Act.</p><p>RELATED ARRANGEMENTS</p><p>Plain language terms: union, delegate, right of entry.</p>',58)])])}const m=t(a,[["render",r]]);export{g as __pageData,m as default};
